#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor conv2d_hswish_relu_impl_npu(const at::Tensor& x,
                                       const at::Tensor& weight,
                                       const c10::optional<at::Tensor>& bias_opt) {
    at::Tensor y = at::empty({x.size(0), weight.size(0),
                              x.size(2) - weight.size(2) + 1,
                              x.size(3) - weight.size(3) + 1}, x.options());
    if (bias_opt.has_value()) {
        EXEC_NPU_CMD(aclnnConv2dHardSwishReluCustom, x, weight, bias_opt.value(), y);
    } else {
        at::Tensor none_bias;
        EXEC_NPU_CMD(aclnnConv2dHardSwishReluCustom, x, weight, none_bias, y);
    }
    return y;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("conv2d_hard_swish_relu_custom", &conv2d_hswish_relu_impl_npu);
}

